import{_ as p,r as o,o as c,c as i,e,a as s,b as a,d as l}from"./app-83da4608.js";const u={},r={href:"https://ollama.com/",target:"_blank",rel:"noopener noreferrer"};function d(k,n){const t=o("ExternalLinkIcon");return c(),i("div",null,[n[4]||(n[4]=e(`<h1 id="_3-3-大语言模型-llm-集成与推理-利用外部或本地模型" tabindex="-1"><a class="header-anchor" href="#_3-3-大语言模型-llm-集成与推理-利用外部或本地模型" aria-hidden="true">#</a> 3.3 大语言模型 (LLM) 集成与推理：利用外部或本地模型</h1><p>虽然 OpenAI 的 GPT 系列模型（如我们项目中默认使用的 <code>gpt-3.5-turbo</code> 或 <code>gpt-4o</code>）非常强大，但在企业级应用中，出于<strong>数据隐私</strong>、<strong>成本控制</strong>和<strong>特定领域表现</strong>的综合考量，我们往往需要集成其他的外部模型，甚至部署完全本地化的开源模型。</p><p>本节我们将探讨如何在现有的 NestJS 项目中，优雅地扩展模型支持。</p><hr><h2 id="_1-为什么需要多模型支持" tabindex="-1"><a class="header-anchor" href="#_1-为什么需要多模型支持" aria-hidden="true">#</a> 1. 为什么需要多模型支持？</h2><p>在构建 AI Agent 时，不同环节对模型能力的要求是不同的：</p><ul><li><strong>复杂推理与任务规划（Agent Loop）</strong>：需要极强的逻辑推理能力，通常依赖 GPT-4o 或 Claude 3.5 Sonnet 等顶级模型。</li><li><strong>简单的数据格式化或意图识别</strong>：只需轻量级模型即可胜任，如 GPT-3.5-turbo 或本地的 Llama 3 8B，可以大幅降低 API 调用成本并提升响应速度。</li><li><strong>高敏感数据处理（如医疗、金融财务数据）</strong>：数据绝对不能出内网，此时必须使用本地部署的开源模型（如 Qwen、DeepSeek 等）。</li></ul><hr><h2 id="_2-外部模型集成-统一的接口抽象" tabindex="-1"><a class="header-anchor" href="#_2-外部模型集成-统一的接口抽象" aria-hidden="true">#</a> 2. 外部模型集成：统一的接口抽象</h2><p>为了不让我们的业务代码（如 <code>AnalysisService</code>）死死绑定在 OpenAI 上，在 NestJS 中，最佳实践是使用<strong>抽象工厂模式 (Factory Pattern)</strong> 或 <strong>策略模式 (Strategy Pattern)</strong> 来管理不同的模型服务。</p><p>目前在我们的 <code>ai-data-analyzer/backend</code> 中，<code>OpenAIService</code> 是这样实现的：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// ai-data-analyzer/backend/src/openai/openai.service.ts (当前实现)</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Injectable<span class="token punctuation">,</span> Logger <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ConfigService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/config&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> OpenAI <span class="token keyword">from</span> <span class="token string">&#39;openai&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Injectable</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">OpenAIService</span> <span class="token punctuation">{</span>
  <span class="token keyword">private</span> <span class="token keyword">readonly</span> openai<span class="token operator">:</span> OpenAI<span class="token punctuation">;</span>
  <span class="token comment">// ...</span>
  <span class="token keyword">async</span> <span class="token function">chat</span><span class="token punctuation">(</span>content<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span> model<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>如何重构以支持多模型？</strong> 我们可以定义一个通用的 <code>ILLMService</code> 接口，然后让不同的提供商服务去实现它：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// 1. 定义统一接口</span>
<span class="token keyword">export</span> <span class="token keyword">interface</span> <span class="token class-name">ILLMService</span> <span class="token punctuation">{</span>
  <span class="token function">chat</span><span class="token punctuation">(</span>prompt<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span> model<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token comment">// 2. 实现 OpenAI 服务</span>
<span class="token decorator"><span class="token at operator">@</span><span class="token function">Injectable</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">OpenAIService</span> <span class="token keyword">implements</span> <span class="token class-name">ILLMService</span> <span class="token punctuation">{</span>
  <span class="token comment">/* ...实现细节... */</span>
<span class="token punctuation">}</span>

<span class="token comment">// ai-data-analyzer/backend/src/openai/claude.service.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Injectable<span class="token punctuation">,</span> Logger <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ConfigService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/config&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> Anthropic <span class="token keyword">from</span> <span class="token string">&#39;@anthropic-ai/sdk&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ILLMService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./llm.interface&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Injectable</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">ClaudeService</span> <span class="token keyword">implements</span> <span class="token class-name">ILLMService</span> <span class="token punctuation">{</span>
  <span class="token keyword">private</span> <span class="token keyword">readonly</span> anthropic<span class="token operator">:</span> Anthropic<span class="token punctuation">;</span>
  <span class="token keyword">private</span> <span class="token keyword">readonly</span> logger <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Logger</span><span class="token punctuation">(</span>ClaudeService<span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token keyword">private</span> configService<span class="token operator">:</span> ConfigService<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> apiKey <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;ANTHROPIC_API_KEY&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>apiKey<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">warn</span><span class="token punctuation">(</span><span class="token string">&#39;ANTHROPIC_API_KEY is not configured.&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">this</span><span class="token punctuation">.</span>anthropic <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Anthropic</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      apiKey<span class="token operator">:</span> apiKey <span class="token operator">||</span> <span class="token string">&#39;dummy-key-for-init&#39;</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token keyword">async</span> <span class="token function">chat</span><span class="token punctuation">(</span>prompt<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">,</span> model<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">try</span> <span class="token punctuation">{</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">debug</span><span class="token punctuation">(</span>
        <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">Sending prompt to Claude (Model: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>model <span class="token operator">||</span> <span class="token string">&#39;claude-3-5-sonnet-20240620&#39;</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">)</span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span>
      <span class="token punctuation">)</span><span class="token punctuation">;</span>

      <span class="token keyword">const</span> response <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>anthropic<span class="token punctuation">.</span>messages<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
        model<span class="token operator">:</span> model <span class="token operator">||</span> <span class="token string">&#39;claude-3-5-sonnet-20240620&#39;</span><span class="token punctuation">,</span>
        max_tokens<span class="token operator">:</span> <span class="token number">1024</span><span class="token punctuation">,</span>
        messages<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token punctuation">{</span> role<span class="token operator">:</span> <span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span> content<span class="token operator">:</span> prompt <span class="token punctuation">}</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
      <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

      <span class="token keyword">const</span> firstBlock <span class="token operator">=</span> response<span class="token punctuation">.</span>content<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
      <span class="token keyword">if</span> <span class="token punctuation">(</span>firstBlock<span class="token punctuation">.</span>type <span class="token operator">===</span> <span class="token string">&#39;text&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> firstBlock<span class="token punctuation">.</span>text<span class="token punctuation">;</span>
      <span class="token punctuation">}</span>
      <span class="token keyword">return</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span>error<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">error</span><span class="token punctuation">(</span><span class="token string">&#39;Failed to call Claude API&#39;</span><span class="token punctuation">,</span> error<span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token keyword">throw</span> error<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>为了让 <code>AnalysisService</code> 彻底与具体模型解耦，我们可以在模块级别（如 <code>OpenAIModule</code> 或 <code>LLMModule</code>）使用 NestJS 的动态 Provider 来决定注入哪一个实现：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// ai-data-analyzer/backend/src/openai/openai.module.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Module <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> OpenAIService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./openai.service&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ClaudeService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;./claude.service&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> ConfigModule<span class="token punctuation">,</span> ConfigService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/config&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Module</span></span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  imports<span class="token operator">:</span> <span class="token punctuation">[</span>ConfigModule<span class="token punctuation">]</span><span class="token punctuation">,</span>
  providers<span class="token operator">:</span> <span class="token punctuation">[</span>
    OpenAIService<span class="token punctuation">,</span>
    ClaudeService<span class="token punctuation">,</span>
    <span class="token punctuation">{</span>
      provide<span class="token operator">:</span> <span class="token string">&#39;LLM_SERVICE&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 依赖注入的 Token</span>
      <span class="token function-variable function">useFactory</span><span class="token operator">:</span> <span class="token punctuation">(</span>
        configService<span class="token operator">:</span> ConfigService<span class="token punctuation">,</span>
        openai<span class="token operator">:</span> OpenAIService<span class="token punctuation">,</span>
        claude<span class="token operator">:</span> ClaudeService<span class="token punctuation">,</span>
      <span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
        <span class="token keyword">const</span> activeModel <span class="token operator">=</span> configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;ACTIVE_LLM_PROVIDER&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token comment">// 根据环境变量决定使用哪个模型服务</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>activeModel <span class="token operator">===</span> <span class="token string">&#39;claude&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
          <span class="token keyword">return</span> claude<span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token keyword">return</span> openai<span class="token punctuation">;</span>
      <span class="token punctuation">}</span><span class="token punctuation">,</span>
      inject<span class="token operator">:</span> <span class="token punctuation">[</span>ConfigService<span class="token punctuation">,</span> OpenAIService<span class="token punctuation">,</span> ClaudeService<span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token comment">// 将原有的 OpenAIService 和 新的 LLM_SERVICE 一起导出，</span>
  <span class="token comment">// 保证旧代码兼容的同时，允许新代码使用 LLM_SERVICE</span>
  exports<span class="token operator">:</span> <span class="token punctuation">[</span>OpenAIService<span class="token punctuation">,</span> <span class="token string">&#39;LLM_SERVICE&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">OpenAIModule</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 <code>AnalysisService</code> 中，我们只需通过 <code>@Inject</code> 装饰器引入这个 Token，业务逻辑无需任何改动：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// ai-data-analyzer/backend/src/analysis/analysis.service.ts</span>
<span class="token keyword">import</span> <span class="token punctuation">{</span> Injectable<span class="token punctuation">,</span> Inject<span class="token punctuation">,</span> Logger <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@nestjs/common&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token keyword">type</span> <span class="token punctuation">{</span> ILLMService <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;../openai/llm.interface&#39;</span><span class="token punctuation">;</span>

<span class="token decorator"><span class="token at operator">@</span><span class="token function">Injectable</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">AnalysisService</span> <span class="token punctuation">{</span>
  <span class="token keyword">private</span> <span class="token keyword">readonly</span> logger <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Logger</span><span class="token punctuation">(</span>AnalysisService<span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// 无论底层是 OpenAI 还是 Claude，这里都能通过依赖注入 Token 无缝接收</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span>
    <span class="token decorator"><span class="token at operator">@</span><span class="token function">Inject</span></span><span class="token punctuation">(</span><span class="token string">&#39;LLM_SERVICE&#39;</span><span class="token punctuation">)</span> <span class="token keyword">private</span> <span class="token keyword">readonly</span> llmService<span class="token operator">:</span> ILLMService<span class="token punctuation">,</span>
  <span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>

  <span class="token keyword">async</span> <span class="token function">analyzeText</span><span class="token punctuation">(</span>rawContent<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">// 业务代码直接调用接口方法</span>
    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>llmService<span class="token punctuation">.</span><span class="token function">chat</span><span class="token punctuation">(</span>rawContent<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这种设计使得我们的 <code>AnalysisService</code> 只需要依赖 <code>ILLMService</code>，无论底层换成什么模型，业务逻辑都不需要修改一行代码。</p><hr><h2 id="_3-本地模型部署与接入-拥抱-ollama" tabindex="-1"><a class="header-anchor" href="#_3-本地模型部署与接入-拥抱-ollama" aria-hidden="true">#</a> 3. 本地模型部署与接入：拥抱 Ollama</h2><p>如果你的数据具有极高的机密性，使用本地模型是最佳选择。目前最简单、最流行的本地大模型运行工具非 <strong>Ollama</strong> 莫属。</p>`,22)),s("p",null,[s("a",r,[n[0]||(n[0]=a("Ollama",-1)),l(t)]),n[1]||(n[1]=a(" 支持 Llama 3, Mistral, 通义千问 (Qwen), DeepSeek 等众多优秀的开源模型，并且",-1)),n[2]||(n[2]=s("strong",null,"它原生提供了完全兼容 OpenAI API 格式的接口",-1)),n[3]||(n[3]=a("！",-1))]),n[5]||(n[5]=e(`<p>这意味着，在我们的项目中接入本地模型，<strong>几乎不需要修改任何代码，只需要修改环境变量！</strong></p><h3 id="接入步骤" tabindex="-1"><a class="header-anchor" href="#接入步骤" aria-hidden="true">#</a> 接入步骤：</h3><p><strong>第一步：安装并运行 Ollama</strong> 在你的本地机器或服务器上安装 Ollama，并拉取/运行一个模型，例如阿里的 Qwen 2.5：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ollama run qwen2.5
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>运行后，Ollama 会在本地启动一个 API 服务，默认地址为 <code>http://localhost:11434</code>。</p><p><strong>第二步：修改 <code>.env</code> 配置文件</strong> 回到我们的 <code>ai-data-analyzer/backend</code> 项目，修改 <code>.env</code> 文件，将基础 URL 指向本地的 Ollama 服务：</p><div class="language-env line-numbers-mode" data-ext="env"><pre class="language-env"><code># 将原来的 OpenAI 配置替换或注释掉
# OPENAI_API_KEY=sk-xxxxxx
# OPENAI_BASE_URL=https://api.openai.com/v1

# 替换为 Ollama 的配置
OPENAI_API_KEY=ollama  # 随便填，Ollama 不需要真实的 API Key
OPENAI_BASE_URL=http://localhost:11434/v1
OPENAI_MODEL=qwen2.5   # 指定你刚才在 Ollama 中拉取的模型名称
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>因为我们的 <code>OpenAIService</code> 在初始化时读取了 <code>OPENAI_BASE_URL</code>：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code>    <span class="token keyword">const</span> baseURL <span class="token operator">=</span> <span class="token keyword">this</span><span class="token punctuation">.</span>configService<span class="token punctuation">.</span><span class="token generic-function"><span class="token function">get</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&#39;OPENAI_BASE_URL&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>openai <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">OpenAI</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      apiKey<span class="token punctuation">,</span>
      baseURL<span class="token punctuation">,</span> <span class="token comment">// 如果环境变量有值，就会使用本地的 Ollama 地址</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>就这样，你的 AI Agent 瞬间就变成了一个完全本地化、断网可用的私有智能体！</p><hr><h2 id="_4-模型路由策略-model-routing" tabindex="-1"><a class="header-anchor" href="#_4-模型路由策略-model-routing" aria-hidden="true">#</a> 4. 模型路由策略 (Model Routing)</h2><p>在实际的企业级 Agent 中，我们通常会混合使用多种模型，这就是<strong>模型路由</strong>。</p><p>你可以在 <code>AnalysisService</code> 中注入多种模型服务，根据任务的难度进行分发：</p><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code>  <span class="token keyword">async</span> <span class="token function">runAgentLoop</span><span class="token punctuation">(</span>rawData<span class="token operator">:</span> <span class="token builtin">any</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span> userPrompt<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">)</span><span class="token operator">:</span> <span class="token builtin">Promise</span><span class="token operator">&lt;</span><span class="token builtin">string</span><span class="token operator">&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">// 1. 先用快速且廉价的本地模型（或 GPT-3.5）进行意图识别</span>
    <span class="token keyword">const</span> intent <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>localLLMService<span class="token punctuation">.</span><span class="token function">chat</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">判断用户请求的难度类别：</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>userPrompt<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token keyword">let</span> aiResponse<span class="token punctuation">;</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>intent<span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span><span class="token string">&#39;COMPLEX_ANALYSIS&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token comment">// 2. 复杂的逻辑推理，交给强大的 GPT-4o</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Routing to GPT-4o for complex reasoning...&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      aiResponse <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>gpt4Service<span class="token punctuation">.</span><span class="token function">chat</span><span class="token punctuation">(</span>conversationHistory<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
      <span class="token comment">// 3. 简单的计算提取，继续使用本地模型</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>logger<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Routing to Local Model for simple task...&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      aiResponse <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token keyword">this</span><span class="token punctuation">.</span>localLLMService<span class="token punctuation">.</span><span class="token function">chat</span><span class="token punctuation">(</span>conversationHistory<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token comment">// ...</span>
  <span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过这种灵活的模型集成与路由策略，我们能够在<strong>智能化水平</strong>、<strong>运行成本</strong>和<strong>数据安全</strong>之间找到完美的平衡点。</p><hr><h2 id="_5-测试与验证" tabindex="-1"><a class="header-anchor" href="#_5-测试与验证" aria-hidden="true">#</a> 5. 测试与验证</h2><p>在完成上述改造后，我们可以在本地启动后端服务进行测试。</p><p><strong>第一步：配置环境变量</strong> 在 <code>.env</code> 文件中添加你想测试的模型配置：</p><div class="language-env line-numbers-mode" data-ext="env"><pre class="language-env"><code># 切换为 claude 即可使用 Claude API
ACTIVE_LLM_PROVIDER=claude
ANTHROPIC_API_KEY=sk-ant-api03-xxxxxxxx
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>第二步：启动后端服务</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">npm</span> run start:dev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>第三步：发送测试请求</strong> 准备一个 <code>test-data.csv</code> 文件：</p><div class="language-csv line-numbers-mode" data-ext="csv"><pre class="language-csv"><code><span class="token value">id</span><span class="token punctuation">,</span><span class="token value">name</span><span class="token punctuation">,</span><span class="token value">amount</span>
<span class="token value">1</span><span class="token punctuation">,</span><span class="token value">Alice</span><span class="token punctuation">,</span><span class="token value">100</span>
<span class="token value">2</span><span class="token punctuation">,</span><span class="token value">Bob</span><span class="token punctuation">,</span><span class="token value">200</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 <code>cURL</code> 向我们之前写好的上传接口发送请求：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> <span class="token parameter variable">-X</span> POST http://localhost:3001/data/upload <span class="token punctuation">\\</span>
  <span class="token parameter variable">-F</span> <span class="token string">&quot;file=@/绝对路径/test-data.csv&quot;</span> <span class="token punctuation">\\</span>
  <span class="token parameter variable">-F</span> <span class="token string">&quot;prompt=请帮我计算金额的总和&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果配置正确，你应该能在后端的控制台（终端）中看到类似这样的日志：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[ClaudeService] Sending prompt to Claude (Model: claude-3-5-sonnet-20240620)
[AnalysisService] AI Response:
Thought: 我需要计算 amount 列的总和。
...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这证明你的动态依赖注入已经完美生效！</p><hr><p>下一节，我们将讨论如何处理大批量的数据、处理流式数据以及实时分析的架构设计。</p>`,32))])}const m=p(u,[["render",d],["__file","3.3 LLM 模型集成与推理：利用外部或本地模型.html.vue"]]);export{m as default};
